mapper.select:
SELECT COALESCE(SUM(I_AMOUNT), 0)
FROM TAB_FUND_FLOW
WHERE I_DIRECTION = #{direction}

    AND D_OCCUR_DATE >= #{startDate}


    AND D_OCCUR_DATE <= #{endDate}

SELECT f.S_CATEGORY_ID   AS sCategoryId,
       c.S_NAME          AS sCategoryName,
       SUM(f.I_AMOUNT)   AS iAmount
FROM TAB_FUND_FLOW f
LEFT JOIN TAB_EXPENSE_CATEGORY c ON c.S_ID = f.S_CATEGORY_ID
WHERE f.I_FLOW_TYPE = #{flowType}

    AND f.D_OCCUR_DATE >= #{startDate}


    AND f.D_OCCUR_DATE <= #{endDate}

GROUP BY f.S_CATEGORY_ID, c.S_NAME
ORDER BY iAmount DESC
